import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import MovieCard from '../components/MovieCard';
import { moviesAPI } from '../utils/api';
import '../styles/Movies.css';

const Movies = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filter, setFilter] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    fetchMovies();
  }, []);

  const fetchMovies = async () => {
    try {
      const response = await moviesAPI.getAll();
      setMovies(response.data);
      setError('');
    } catch (error) {
      setError('Failed to load movies');
      console.error('Error fetching movies:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = (movieId) => {
    setMovies(movies.filter(movie => movie._id !== movieId));
  };

  // Фильтрация: сначала по статусу, потом по поисковому запросу
  const filteredMovies = movies
    .filter(movie => filter === 'all' || movie.status === filter)
    .filter(movie => movie.title.toLowerCase().includes(searchQuery.toLowerCase()));

  const stats = {
    total: movies.length,
    watched: movies.filter(m => m.status === 'watched').length,
    watching: movies.filter(m => m.status === 'watching').length,
    plan: movies.filter(m => m.status === 'plan to watch').length
  };

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="movies-page">
      <div className="movies-container">
        <div className="movies-header">
          <h1>
            My <span className="highlight">Movie Watchlist</span>
          </h1>

          {/* Блок статистики */}
          <div className="stats-container">
            <div className="stat-card">
              <div className="stat-value">{stats.total}</div>
              <div className="stat-label">
                <h3>Total</h3>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{stats.watched}</div>
              <div className="stat-label">
                <h3>Watched</h3>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{stats.watching}</div>
              <div className="stat-label">
                <h3>Watching</h3>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{stats.plan}</div>
              <div className="stat-label">
                <h3>Plan to Watch</h3>
              </div>
            </div>
          </div>

          {/* Поиск и фильтр: Точная копия стилей из MovieForm */}
          <div className="search-filter-container">
            <div className="input-box">
              <input
                type="text"
                placeholder="Search by title..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <i className='bx bx-search'></i>
            </div>

            <div className="input-box">
              <select 
                value={filter} 
                onChange={(e) => setFilter(e.target.value)}
                className={filter === 'all' ? 'unselected' : 'selected'}
              >
                <option value="all">All Movies</option>
                <option value="watched">Watched</option>
                <option value="watching">Watching</option>
                <option value="plan to watch">Plan to Watch</option>
              </select>
              <i className='bx bx-chevron-down'></i>
            </div>
          </div>
        </div>

        {error && <div className="error-message">{error}</div>}

        {filteredMovies.length === 0 ? (
          <div className="no-movies">
            <p>No movies found. Start adding some!</p>
            <Link to="/movies/add" className="btn btn-primary">
              Add Your First Movie
            </Link>
          </div>
        ) : (
          <div className="movies-grid">
            {filteredMovies.map(movie => (
              <MovieCard 
                key={movie._id} 
                movie={movie} 
                onDelete={handleDelete}
              />
            ))}
          </div>
        )}
      </div>

      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <div className="footer-logo">
              <img src="/Filmery.png" alt="Watchlist Logo" className="footer-logo-img" />
              <h3>Filmery</h3>
            </div>
            <p>Your personal movie tracking companion. Never forget a great film again.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><Link to="/">Home</Link></li>
              <li><Link to="/movies">My Watchlist</Link></li>
              <li><Link to="/login">Login</Link></li>
              <li><Link to="/register">Register</Link></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Features</h4>
            <ul>
              <li>Track Movies</li>
              <li>Rate & Review</li>
              <li>Statistics</li>
              <li>Private Lists</li>
            </ul>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; 2026 Movie Watchlist. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default Movies;
